#include<iostream>
#include<cstdio>
#include<algorithm>
using namespace std;

int main()
{
    int n;
    cin >> n;
    int minx = 2e9, miny = 2e9, maxx = -2e9, maxy =-2e9;
    for(int i = 1; i <= n; i++){
        int x, y, x2, y2;
        cin >> x >> y >> x2 >> y2;
        minx = min(minx, x);
        maxx = max(maxx, x);
        miny = min(miny, y);
        maxy = max(maxy, y);
        minx = min(minx, x2);
        maxx = max(maxx, x2);
        miny = min(miny, y2);
        maxy = max(maxy, y2);
    }
    cout << (1ll * (maxx - minx) * (maxy - miny)) << endl;
    return 0;
}
